SELECT avg_likes_per_day
FROM like_statistics
WHERE user_id = 1;

SELECT friendship_status, COUNT(*) 
FROM friendships 
GROUP BY friendship_status;

SELECT DISTINCT f1.user_id AS User1, f1.friend_id AS User2
FROM friendships f1
JOIN friendships f2 ON f1.user_id = f2.friend_id AND f1.friend_id = f2.user_id;

SELECT COUNT(*)
FROM (
    SELECT user_id
    FROM like_statistics
    WHERE total_likes > (SELECT AVG(total_likes) FROM like_statistics)
) AS users_more_likes;

SELECT s.platform_name, f.max_friends_per_day
FROM friendship_statistics AS f
JOIN social_media_platforms AS s ON f.platform_id = s.platform_id
WHERE f.max_friends_per_day = (
    SELECT MAX(max_friends_per_day) FROM friendship_statistics
);

SELECT total_likes
FROM like_statistics
WHERE user_id = 0;
